script:
frappe.ui.form.on("Employee Checkin", {
    refresh(frm) {
        _set_project_filter(frm);
    },
    employee(frm) {
        _set_project_filter(frm);
        frm.set_value("custom_project", "");
    },
    time(frm) {
        _set_project_filter(frm);
    }
});

function _set_project_filter(frm) {
    const employee = frm.doc.employee;
    if (!employee) return;
    const date = frm.doc.time
        ? frappe.datetime.str_to_obj(frm.doc.time).toISOString().slice(0, 10)
        : frappe.datetime.get_today();

    frappe.call({
        method: "cooperheat.cooperheat.api.api.get_assigned_projects",
        args: { employee, date },
        callback(r) {
            const projects = r.message || [];
            if (!projects.length) {
                frm.set_query("custom_project", () => ({}));
                return;
            }
            frm.set_query("custom_project", () => ({
                filters: [["Project", "name", "in", projects]]
            }));
        }
    });
}

frappe.ui.form.on("Attendance", {
    refresh(frm) {
        if (frm.doc.docstatus === 1 && frappe.user.has_role("HR Manager")) {
            frm.add_custom_button(__("Recalculate Site Hours"), () => {
                frappe.call({
                    method: "cooperheat.cooperheat.api.api.recalculate_site_hours",
                    args: { attendance_name: frm.docname },
                    callback(r) {
                        if (r.message && r.message.status === "ok") {
                            frappe.msgprint(__("Site hours recalculated."));
                            frm.reload_doc();
                        }
                    }
                });
            }, __("Actions"));
        }
    }
});

frappe.ui.form.on('Attendance', {
    refresh(frm) {
        cooperheat_hide_help_button(frm);
        cooperheat_toggle_site_hours_section(frm);
        cooperheat_control_approval_access(frm);
        cooperheat_add_recalculate_button(frm);
    },
    in_time(frm) {
        cooperheat_recalculate_hours(frm);
    },
    out_time(frm) {
        cooperheat_recalculate_hours(frm);
    }
});

frappe.ui.form.on('Attendance Site Hours', {
    check_in_time(frm, cdt, cdn) {
        cooperheat_recalculate_row_hours(frm, cdt, cdn);
    },
    check_out_time(frm, cdt, cdn) {
        cooperheat_recalculate_row_hours(frm, cdt, cdn);
    },
    hours(frm, cdt, cdn) {
        cooperheat_sync_attendance_times_from_rows(frm);
    }
});

function cooperheat_recalculate_row_hours(frm, cdt, cdn) {
    const row = locals[cdt][cdn];
    if (row.check_in_time && row.check_out_time) {
        const inn = frappe.datetime.str_to_obj(row.check_in_time);
        const out = frappe.datetime.str_to_obj(row.check_out_time);
        if (out > inn) {
            const hours = Math.round((out - inn) / (1000 * 3600) * 100) / 100;
            frappe.model.set_value(cdt, cdn, 'hours', hours);
        }
    }
    cooperheat_sync_attendance_times_from_rows(frm);
}

function cooperheat_sync_attendance_times_from_rows(frm) {
    const rows = frm.doc.custom_site_hours || [];
    let total_hours = 0;
    let min_in = null, max_out = null;
    rows.forEach(row => {
        total_hours += flt(row.hours || 0);
        // Compare datetime strings directly — lexicographic order works for YYYY-MM-DD HH:mm:ss
        if (row.check_in_time) {
            if (!min_in || row.check_in_time < min_in) min_in = row.check_in_time;
        }
        if (row.check_out_time) {
            if (!max_out || row.check_out_time > max_out) max_out = row.check_out_time;
        }
    });
    frm.set_value('working_hours', Math.round(total_hours * 100) / 100);
    if (min_in) frm.set_value('in_time', min_in);
    if (max_out) frm.set_value('out_time', max_out);
}

function cooperheat_toggle_site_hours_section(frm) {
    // Force-show both the section break and the child table on every refresh.
    // For submitted records the approver must be able to add rows even when absent.
    frm.toggle_display(['custom_site_hours_section', 'custom_site_hours'], true);
    // Belt-and-suspenders: directly set the wrapper visible in case Frappe hid it.
    const sf = frm.fields_dict['custom_site_hours_section'];
    const tf = frm.fields_dict['custom_site_hours'];
    if (sf && sf.$wrapper) sf.$wrapper.show();
    if (tf && tf.$wrapper) tf.$wrapper.show();
}

function cooperheat_add_recalculate_button(frm) {
    if (frm.doc.docstatus !== 1) return;
    const pending_states = ['Pending Level 1 Approval', 'Pending Level 2 Approval', 'Pending Level 3 Approval'];
    const is_hr = frappe.user.has_role('HR Manager');
    const is_pending = pending_states.includes(frm.doc.workflow_state);
    if (!is_hr && !is_pending) return;  // show to HR Manager always; show to approver when pending
    frm.add_custom_button(__('Recalculate Site Hours'), () => {
        frappe.call({
            method: 'cooperheat.cooperheat.api.api.recalculate_site_hours',
            args: { attendance_name: frm.doc.name },
            callback(r) {
                if (r && !r.exc) {
                    frappe.show_alert({ message: __('Site hours recalculated'), indicator: 'green' });
                    frm.reload_doc();
                }
            }
        });
    }, __('Actions'));
}

function cooperheat_recalculate_hours(frm) {
    if (frm.doc.in_time && frm.doc.out_time) {
        const inn = frappe.datetime.str_to_obj(frm.doc.in_time);
        const out = frappe.datetime.str_to_obj(frm.doc.out_time);
        if (out > inn) {
            const hours = (out - inn) / (1000 * 3600);
            frm.set_value('working_hours', Math.round(hours * 100) / 100);
        }
    }
}

function cooperheat_hide_help_button(frm) {
    setTimeout(() => {
        frm.page.actions_btn_group.find('a').each(function () {
            if ($(this).text().trim() === 'Help') {
                $(this).parent().hide();
            }
        });
    }, 500);
}

function cooperheat_lock_site_hours_columns(grid) {
    try { grid.toggle_enable('project', false); } catch(e) {}
    try { grid.toggle_enable('check_in_time', false); } catch(e) {}
    try { grid.toggle_enable('check_out_time', false); } catch(e) {}
    try { grid.toggle_enable('hours', false); } catch(e) {}
}

function cooperheat_unlock_site_hours_columns(grid) {
    try { grid.toggle_enable('project', true); } catch(e) {}
    try { grid.toggle_enable('check_in_time', true); } catch(e) {}
    try { grid.toggle_enable('check_out_time', true); } catch(e) {}
    try { grid.toggle_enable('hours', true); } catch(e) {}
}

function cooperheat_lock_attendance_fields(frm) {
    ['status', 'in_time', 'out_time', 'working_hours'].forEach(f => {
        frm.set_df_property(f, 'read_only', 1);
    });
    frm.refresh_fields(['status', 'in_time', 'out_time', 'working_hours']);

    // Do NOT set read_only on the Table field itself — Frappe hides empty read-only
    // tables which makes the section invisible on Absent records.
    // Control editability via grid.display_status only.
    const grid = frm.fields_dict['custom_site_hours'] && frm.fields_dict['custom_site_hours'].grid;
    if (grid) {
        cooperheat_lock_site_hours_columns(grid);
        grid.display_status = 'Read';
        grid.setup_toolbar();
        grid.refresh();
        grid.toggle_checkboxes(false);
    }
}

function cooperheat_unlock_attendance_fields(frm) {
    if (frm.perm && frm.perm[0]) frm.perm[0].write = 1;
    ['status', 'in_time', 'out_time', 'working_hours'].forEach(f => {
        frm.set_df_property(f, 'read_only', 0);
    });
    frm.refresh_fields(['status', 'in_time', 'out_time', 'working_hours']);

    const grid = frm.fields_dict['custom_site_hours'] && frm.fields_dict['custom_site_hours'].grid;
    if (grid) {
        cooperheat_unlock_site_hours_columns(grid);
        grid.display_status = 'Write';
        grid.setup_toolbar();
        grid.refresh();
        grid.toggle_checkboxes(true);
    }
}

function cooperheat_hide_action_buttons(frm) {
    setTimeout(() => {
        const action_labels = ['Level 1 Approve', 'Level 2 Approve', 'Level 3 Approve', 'Reject'];
        frm.page.actions_btn_group.find('a').each(function () {
            if (action_labels.includes($(this).text().trim())) {
                $(this).parent().hide();
            }
        });
        frm.page.inner_btn_group && frm.page.inner_btn_group.find('button').each(function () {
            if (action_labels.includes($(this).text().trim())) {
                $(this).hide();
            }
        });
        cooperheat_lock_attendance_fields(frm);
    }, 500);
}

function cooperheat_control_approval_access(frm) {
    if (frm.doc.docstatus !== 1) return;

    cooperheat_lock_attendance_fields(frm);

    const live_doc = frappe.get_doc(frm.doctype, frm.docname) || frm.doc;

    const level_map = {
        'Pending Level 1 Approval': 1,
        'Pending Level 2 Approval': 2,
        'Pending Level 3 Approval': 3,
    };
    const level = level_map[live_doc.workflow_state];
    if (!level || !frm.doc.department) return;

    const window_expires_at = live_doc.window_expires_at;
    if (window_expires_at && frappe.datetime.now_datetime() > window_expires_at) {
        cooperheat_hide_action_buttons(frm);
        return;
    }

    frappe.call({
        method: 'cooperheat.cooperheat.api.api.get_approval_matrix_approver',
        args: { department: frm.doc.department, level: level },
        callback(r) {
            if (!r || !r.message || !r.message.user_id) {
                cooperheat_hide_action_buttons(frm);
                return;
            }
            if (r.message.user_id === frappe.session.user) {
                cooperheat_unlock_attendance_fields(frm);
            } else {
                cooperheat_hide_action_buttons(frm);
            }
        }
    });
}

frappe.ui.form.on('Employee Checkin', {
    refresh(frm) {
        cooperheat_set_project_filter(frm);
    },
    employee(frm) {
        frm.set_value('custom_project', '');
        cooperheat_set_project_filter(frm);
    },
    time(frm) {
        cooperheat_set_project_filter(frm);
    },
    log_type(frm) {
        if (frm.doc.log_type === 'OUT' && frm.doc.employee && !frm.doc.custom_project) {
            cooperheat_copy_project_from_last_checkin(frm);
        }
        cooperheat_set_project_filter(frm);
    }
});

function cooperheat_copy_project_from_last_checkin(frm) {
    const date = frm.doc.time ? frm.doc.time.split(' ')[0] : frappe.datetime.get_today();
    frappe.db.get_list('Employee Checkin', {
        filters: {
            employee: frm.doc.employee,
            log_type: 'IN',
            time: ['>=', date + ' 00:00:00']
        },
        fields: ['custom_project'],
        order_by: 'time desc',
        limit: 1
    }).then(rows => {
        if (rows && rows.length && rows[0].custom_project) {
            frm.set_value('custom_project', rows[0].custom_project);
        }
    });
}

function cooperheat_set_project_filter(frm) {
    if (!frm.doc.employee || !frm.doc.time) {
        frm.set_query('custom_project', () => ({ filters: [] }));
        return;
    }
    const date = frm.doc.time.split(' ')[0];
    frappe.call({
        method: 'cooperheat.cooperheat.api.api.get_assigned_projects',
        args: { employee: frm.doc.employee, date: date },
        callback(r) {
            const projects = (r && r.message) || [];
            if (projects.length) {
                frm.set_query('custom_project', () => ({
                    filters: [['Project', 'name', 'in', projects]]
                }));
            } else {
                frm.set_query('custom_project', () => ({ filters: [] }));
            }
        }
    });
}

frappe.listview_settings['Attendance'] = frappe.listview_settings['Attendance'] || {};

const _ch_prev_onload = frappe.listview_settings['Attendance'].onload;
frappe.listview_settings['Attendance'].onload = function(listview) {
    _ch_prev_onload && _ch_prev_onload(listview);

    // Button opens the dedicated Level 3 Approval page where the approver
    // can also edit working hours, in-time, and out-time before approving.
    listview.page.add_inner_button(__('Level 3 Approval Page'), function() {
        frappe.set_route('level-3-approval');
    });
};

frappe.ui.form.on('Attendance Site Hours', {
    check_in_time(frm, cdt, cdn) {
        if (frm.doctype !== 'Attendance Request') return;
        _ch_ar_recalc_site_hours(cdt, cdn);
    },
    check_out_time(frm, cdt, cdn) {
        if (frm.doctype !== 'Attendance Request') return;
        _ch_ar_recalc_site_hours(cdt, cdn);
    },
});

function _ch_ar_recalc_site_hours(cdt, cdn) {
    const row = locals[cdt][cdn];
    if (!row.check_in_time || !row.check_out_time) return;
    const inn = frappe.datetime.str_to_obj(row.check_in_time);
    const out = frappe.datetime.str_to_obj(row.check_out_time);
    if (out > inn) {
        const hours = Math.round((out - inn) / (1000 * 3600) * 100) / 100;
        frappe.model.set_value(cdt, cdn, 'hours', hours);
    }
}
